pre-actions.script:
// if user not logged in save current path and params then redirect to Login
if (!ec.user.userId) { ec.web.saveScreenLastInfo(null, null); sri.sendRedirectAndStopRender('/Login') }

// Stylesheets -- loaded explicitly here because seed-initial theme data (DEFAULT_QUASAR2)
// may not be in DB if the first server startup had a component error before data loading.
// Mirrors WebrootQuasar2ThemeData.xml STRT_STYLESHEET resources.
html_stylesheets.add('/libs/font-awesome/css/font-awesome.min.css')
html_stylesheets.add('https://fonts.googleapis.com/css?family=Roboto:100,300,400,500,700,900|Material+Icons')
html_stylesheets.add('/libs/quasar2/quasar.min.css')
html_stylesheets.add('/css/WebrootVue.qvt.css')

html_scripts.add('/libs/moment.js/moment-with-locales.min.js')
html_scripts.add('/libs/jquery/jquery.min.js')

String instancePurpose = System.getProperty("instance_purpose")
if (!instancePurpose || instancePurpose == 'production') {
    /* ========== Production Mode ========== */
    html_scripts.add('/js/MoquiLib.min.js')
    // Vue JS 3 (global build, exposes window.Vue)
    footer_scripts.add('/libs/vue3/vue.min.js')
    // vue-demi -- must load after Vue, before Pinia (Pinia IIFE requires window.VueDemi)
    footer_scripts.add('/libs/vue-demi/vue-demi.iife.min.js')
    // Pinia 2 -- must load after vue-demi, before Quasar and WebrootVue
    footer_scripts.add('/libs/pinia/pinia.umd.min.js')
    // http-vue-loader
    footer_scripts.add('/js/http-vue-loader/httpVueLoader.js')
    // Quasar 2
    footer_scripts.add('/libs/quasar2/quasar.umd.min.js')
    // Pinia store definitions -- must load after Pinia, before WebrootVue
    footer_scripts.add('/js/MoquiStore.js')
    // Webroot Quasar 2 / Vue 3 instance, in footer so runs after page loaded
    footer_scripts.add('/js/WebrootVue.qvt2.min.js')
} else {
    /* ========== Dev Mode ========== */
    html_scripts.add('/js/MoquiLib.js')
    // Vue JS 3 (global build, exposes window.Vue)
    footer_scripts.add('/libs/vue3/vue.js')
    // vue-demi -- must load after Vue, before Pinia (Pinia IIFE requires window.VueDemi)
    footer_scripts.add('/libs/vue-demi/vue-demi.iife.min.js')
    // Pinia 2 -- must load after vue-demi, before Quasar and WebrootVue
    footer_scripts.add('/libs/pinia/pinia.umd.min.js')
    // http-vue-loader
    footer_scripts.add('/js/http-vue-loader/httpVueLoader.js')
    // Quasar 2
    footer_scripts.add('/libs/quasar2/quasar.umd.min.js')
    // Pinia store definitions -- must load after Pinia, before WebrootVue
    footer_scripts.add('/js/MoquiStore.js')
    // Webroot Quasar 2 / Vue 3 instance, in footer so runs after page loaded
    footer_scripts.add('/js/WebrootVue.qvt2.js')
}

// conditional QZ Tray scripts, only include if enabled
if (ec.user.getPreference("qz.print.enabled") == "true") {
    footer_scripts.add('/js/qz-tray/sha-256.min.js')
    footer_scripts.add('/js/qz-tray/qz-tray.min.js')
    footer_scripts.add('/js/qz-tray/MoquiQzComponent.js')
}
